export function getTodaySaint() {
  const now = new Date();
  return getSaintByDate(now.getMonth() + 1, now.getDate());
}

export function getSaintByDate(month, day) {
  const monthData = CALENDAR_DATA[month];
  if (!monthData) return null;
  return monthData.find(e => e.day === day) || null;
}

export function getMonthSaints(month) {
  return CALENDAR_DATA[month] || [];
}

export function getFastingLabel(fasting) {
  const labels = {
    'none': 'Без ограничења',
    'fish': 'Риба',
    'oil': 'Уље',
    'strict': 'Строги пост',
  };
  return labels[fasting] || fasting;
}

export function getTypeLabel(type) {
  const labels = {
    'great': 'Велики празник',
    'major': 'Празник',
    'regular': 'Обичан дан',
  };
  return labels[type] || type;
}

export default CALENDAR_DATA;
